import{_ as e,o as l,c as r,ae as i}from"./chunks/framework.C1F7hH3b.js";const c=JSON.parse('{"title":"我开发了一个 VSCode 插件《markdown-publisher-for-all》，支持 Markdown 多平台一键发布","description":"","frontmatter":{},"headers":[],"relativePath":"blog/由于喜欢写博文，我写了个vscode插件《markdown-publisher-for-all》，支持markdown多平台一键发布.md","filePath":"blog/由于喜欢写博文，我写了个vscode插件《markdown-publisher-for-all》，支持markdown多平台一键发布.md","lastUpdated":1779089352000}'),o={name:"blog/由于喜欢写博文，我写了个vscode插件《markdown-publisher-for-all》，支持markdown多平台一键发布.md"};function s(t,a,h,n,d,u){return l(),r("div",null,[...a[0]||(a[0]=[i(`<h1 id="我开发了一个-vscode-插件《markdown-publisher-for-all》-支持-markdown-多平台一键发布" tabindex="-1">我开发了一个 VSCode 插件《markdown-publisher-for-all》，支持 Markdown 多平台一键发布 <a class="header-anchor" href="#我开发了一个-vscode-插件《markdown-publisher-for-all》-支持-markdown-多平台一键发布" aria-label="Permalink to &quot;我开发了一个 VSCode 插件《markdown-publisher-for-all》，支持 Markdown 多平台一键发布&quot;">​</a></h1><p>作为一个热爱写技术博客的人，我经常需要将自己的文章发布到多个平台上，比如 CSDN、简书、知乎、掘金等。但每次手动复制粘贴内容，再上传图片，不仅效率低下，还容易出错。因此，我决定开发一个 VSCode 插件来解决这个问题。</p><h2 id="什么是-markdown-publisher-for-all" tabindex="-1">什么是 markdown-publisher-for-all？ <a class="header-anchor" href="#什么是-markdown-publisher-for-all" aria-label="Permalink to &quot;什么是 markdown-publisher-for-all？&quot;">​</a></h2><p>markdown-publisher-for-all 是一个基于 VSCode 的博文发布客户端，能够一键将 Markdown 文章发布到多个主流博客平台，无需额外的图床服务。</p><blockquote><p>项目由个人独立开发，专注于提高博主们的发布效率。</p></blockquote><p>你可以在 VSCode 插件市场找到它：<a href="https://marketplace.visualstudio.com/items?itemName=brother-xiaohei.markdown-publisher-for-all&amp;ssr=false#overview" target="_blank" rel="noreferrer">markdown-publisher-for-all</a></p><h2 id="主要特性" tabindex="-1">主要特性 <a class="header-anchor" href="#主要特性" aria-label="Permalink to &quot;主要特性&quot;">​</a></h2><h3 id="_1-二维码登录" tabindex="-1">1. 二维码登录 <a class="header-anchor" href="#_1-二维码登录" aria-label="Permalink to &quot;1. 二维码登录&quot;">​</a></h3><p>通过扫描二维码快速登录各个平台，免去账号密码的繁琐流程。</p><h3 id="_2-一键多平台发布" tabindex="-1">2. 一键多平台发布 <a class="header-anchor" href="#_2-一键多平台发布" aria-label="Permalink to &quot;2. 一键多平台发布&quot;">​</a></h3><p>支持将同一篇文章同时发布到多个平台，包括：</p><ul><li>CSDN</li><li>简书</li><li>知乎</li><li>掘金</li><li>其他主流博客平台</li></ul><h3 id="_3-图片自动上传" tabindex="-1">3. 图片自动上传 <a class="header-anchor" href="#_3-图片自动上传" aria-label="Permalink to &quot;3. 图片自动上传&quot;">​</a></h3><p>智能识别 Markdown 中的图片链接，并自动上传到对应平台的图床服务，无需手动上传。</p><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><h3 id="初始配置" tabindex="-1">初始配置 <a class="header-anchor" href="#初始配置" aria-label="Permalink to &quot;初始配置&quot;">​</a></h3><h4 id="step-1-安装-chrome-浏览器" tabindex="-1">Step 1: 安装 Chrome 浏览器 <a class="header-anchor" href="#step-1-安装-chrome-浏览器" aria-label="Permalink to &quot;Step 1: 安装 Chrome 浏览器&quot;">​</a></h4><p>目前插件仅支持 Chrome 浏览器，你需要：</p><ol><li>安装最新版的 Chrome 浏览器</li><li>在浏览器地址栏输入 <code>chrome://version/</code> 获取浏览器信息</li><li>记录下 &quot;Executable Path&quot; 和 &quot;User Data Directory&quot; 的值</li></ol><h4 id="step-2-配置插件设置" tabindex="-1">Step 2: 配置插件设置 <a class="header-anchor" href="#step-2-配置插件设置" aria-label="Permalink to &quot;Step 2: 配置插件设置&quot;">​</a></h4><p>在工作区的 [.vscode/settings.json]文件中添加以下配置：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;MarkdownPublisher.ChromeExecutablePath&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;你的 Chrome 可执行文件路径&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;MarkdownPublisher.ChromeUserDataDir&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;你的 Chrome 用户数据目录路径&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h3><ol><li>打开一个编写好的 Markdown 文件</li><li>在编辑器中右键点击</li><li>选择需要发布的目标平台</li><li>插件会自动处理内容并发布到相应平台</li></ol><h2 id="更新日志-changelog" tabindex="-1">更新日志 (Changelog) <a class="header-anchor" href="#更新日志-changelog" aria-label="Permalink to &quot;更新日志 (Changelog)&quot;">​</a></h2><h3 id="v1-4-0-planning" tabindex="-1">V1.4.0 [Planning] <a class="header-anchor" href="#v1-4-0-planning" aria-label="Permalink to &quot;V1.4.0 [Planning]&quot;">​</a></h3><ul><li>加入思否平台的支持</li></ul><h3 id="v1-3-6-released" tabindex="-1">V1.3.6 [Released] <a class="header-anchor" href="#v1-3-6-released" aria-label="Permalink to &quot;V1.3.6 [Released]&quot;">​</a></h3><ul><li>解决Windows下图片上传的路径问题</li></ul><h3 id="v1-3-2-released" tabindex="-1">V1.3.2 [Released] <a class="header-anchor" href="#v1-3-2-released" aria-label="Permalink to &quot;V1.3.2 [Released]&quot;">​</a></h3><ul><li>掘金平台图片上传流程修改</li></ul><h3 id="v1-3-0-released" tabindex="-1">V1.3.0 [Released] <a class="header-anchor" href="#v1-3-0-released" aria-label="Permalink to &quot;V1.3.0 [Released]&quot;">​</a></h3><ul><li>加入知乎平台的支持</li></ul><h3 id="v1-2-0-released" tabindex="-1">V1.2.0 [Released] <a class="header-anchor" href="#v1-2-0-released" aria-label="Permalink to &quot;V1.2.0 [Released]&quot;">​</a></h3><ul><li>加入掘金平台的支持</li></ul><h3 id="v1-1-0-released" tabindex="-1">V1.1.0 [Released] <a class="header-anchor" href="#v1-1-0-released" aria-label="Permalink to &quot;V1.1.0 [Released]&quot;">​</a></h3><ul><li>加入简书的支持</li><li>添加配置uploadImageTogether，可控制文章配图是否需要上传</li></ul><h3 id="v1-0-0-released" tabindex="-1">V1.0.0 [Released] <a class="header-anchor" href="#v1-0-0-released" aria-label="Permalink to &quot;V1.0.0 [Released]&quot;">​</a></h3><ul><li>核心功能完成</li><li>完成对CSDN的一键发文</li></ul><h2 id="问题反馈" tabindex="-1">问题反馈 <a class="header-anchor" href="#问题反馈" aria-label="Permalink to &quot;问题反馈&quot;">​</a></h2><p>如果你在使用过程中遇到任何问题，或者有功能建议，欢迎到我的 CSDN 博客留言交流。我将持续改进这个工具，为大家提供更好的体验。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>这个插件解决了我自己的痛点，也希望能帮助更多热爱写作的技术人。让我们专注于创作内容本身，而不是繁琐的发布流程。</p><blockquote><p>Now, Enjoy!</p></blockquote>`,44)])])}const k=e(o,[["render",s]]);export{c as __pageData,k as default};
